import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";

function Courses() {
  const user = useSelector((state) => state.auth.user);
  const [courses, setCourses] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [tests, setTests] = useState([]);
  const [files, setFiles] = useState([]);
  const [studentUploads, setStudentUploads] = useState([]);
  const [uploadFiles, setUploadFiles] = useState({}); // Для хранения файлов для загрузки

  useEffect(() => {
    if (user?.role === "student" && user?.id && user?.classId) {
      console.log("Fetching enrollments for user:", user.id);
      fetch(`http://localhost:3001/enrollments?userId=${user.id}`)
        .then((res) => res.json())
        .then((data) => {
          console.log("Enrollments data:", data);
          const enrollmentsArray = Array.isArray(data) ? data : [];
          setEnrollments(enrollmentsArray);
          fetch(`http://localhost:3001/courses?classId=${user.classId}`)
            .then((res) => res.json())
            .then((courseData) => {
              console.log("Courses data:", courseData);
              const coursesArray = Array.isArray(courseData) ? courseData : [];
              setCourses(coursesArray);
              if (coursesArray.length > 0) {
                const courseIds = coursesArray.map((c) => c.id);
                fetch(`http://localhost:3001/files?courseId=${courseIds.join("&courseId=")}`)
                  .then((res) => res.json())
                  .then((fileData) => {
                    console.log("Files data:", fileData);
                    setFiles(Array.isArray(fileData) ? fileData : []);
                  })
                  .catch((error) => {
                    console.error("Files fetch error:", error);
                    toast.error("Ошибка загрузки файлов");
                  });
                fetch(`http://localhost:3001/student_uploads?userId=${user.id}&courseId=${courseIds.join("&courseId=")}`)
                  .then((res) => res.json())
                  .then((uploadData) => {
                    console.log("Student uploads data:", uploadData);
                    setStudentUploads(Array.isArray(uploadData) ? uploadData : []);
                  })
                  .catch((error) => {
                    console.error("Student uploads fetch error:", error);
                    toast.error("Ошибка загрузки отправленных файлов");
                  });
              }
            })
            .catch((error) => {
              console.error("Courses fetch error:", error);
              toast.error("Ошибка загрузки курсов");
              setCourses([]);
            });
          const courseIds = enrollmentsArray.map((e) => e.courseId);
          if (courseIds.length > 0) {
            fetch(`http://localhost:3001/tests?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((testData) => {
                console.log("Tests data:", testData);
                setTests(Array.isArray(testData) ? testData : []);
              })
              .catch((error) => {
                console.error("Tests fetch error:", error);
                toast.error("Ошибка загрузки тестов");
              });
          } else {
            setTests([]);
          }
        })
        .catch((error) => {
          console.error("Enrollments fetch error:", error);
          toast.error("Ошибка загрузки записей");
          setEnrollments([]);
        });
    } else if (user?.role === "teacher" && user?.id) {
      console.log("Fetching courses for teacher:", user.id);
      fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((data) => {
          console.log("Teacher courses data:", data);
          const coursesArray = Array.isArray(data) ? data : [];
          setCourses(coursesArray);
          if (coursesArray.length > 0) {
            const courseIds = coursesArray.map((c) => c.id);
            fetch(`http://localhost:3001/files?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((fileData) => {
                console.log("Teacher files data:", fileData);
                setFiles(Array.isArray(fileData) ? fileData : []);
              })
              .catch((error) => {
                console.error("Teacher files fetch error:", error);
                toast.error("Ошибка загрузки файлов");
              });
            fetch(`http://localhost:3001/student_uploads?courseId=${courseIds.join("&courseId=")}`)
              .then((res) => res.json())
              .then((uploadData) => {
                console.log("Student uploads for teacher:", uploadData);
                setStudentUploads(Array.isArray(uploadData) ? uploadData : []);
              })
              .catch((error) => {
                console.error("Student uploads fetch error for teacher:", error);
                toast.error("Ошибка загрузки файлов студентов");
              });
          }
        })
        .catch((error) => {
          console.error("Teacher courses fetch error:", error);
          toast.error("Ошибка загрузки курсов");
        });
    } else {
      console.log("Invalid user data:", user);
    }
  }, [user]);

  const handleFileChange = (courseId, e) => {
    setUploadFiles((prev) => ({
      ...prev,
      [courseId]: e.target.files[0],
    }));
  };

  const handleFileUpload = async (courseId, e) => {
    e.preventDefault();
    const file = uploadFiles[courseId];
    if (!file) {
      toast.error("Выберите файл для загрузки!");
      return;
    }
    const formData = new FormData();
    formData.append("file", file);
    try {
      const response = await fetch("http://localhost:3002/upload", {
        method: "POST",
        body: formData,
      });
      if (response.ok) {
        const { filename, originalName } = await response.json();
        const uploadData = {
          courseId: parseInt(courseId),
          userId: user.id,
          filename,
          originalName,
          path: `uploads/${filename}`,
          createdAt: new Date().toISOString(),
        };
        const uploadResponse = await fetch("http://localhost:3001/student_uploads", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(uploadData),
        });
        if (uploadResponse.ok) {
          toast.success("Файл успешно загружен!");
          setUploadFiles((prev) => ({ ...prev, [courseId]: null }));
          const updatedUploads = await fetch(`http://localhost:3001/student_uploads?userId=${user.id}&courseId=${courseId}`)
            .then((res) => res.json());
          setStudentUploads(updatedUploads);
          await fetch("http://localhost:3001/notifications", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              userId: user.id,
              message: `Студент загрузил файл "${originalName}" для курса ID ${courseId}.`,
              createdAt: new Date().toISOString(),
            }),
          });
        } else {
          toast.error("Не удалось сохранить данные файла");
        }
      } else {
        toast.error("Не удалось загрузить файл");
      }
    } catch (error) {
      console.error("File upload error:", error);
      toast.error("Сетевая ошибка при загрузке файла");
    }
  };

  if (!user) {
    return <div className="container mt-5"><h1>Пожалуйста, войдите в систему</h1></div>;
  }

  if (user.role === "student" && !user.classId) {
    return <div className="container mt-5"><h1>У вас не указан класс. Обратитесь к администратору.</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Курсы</h1>
      <div className="card shadow">
        <div className="card-body">
          <h2 className="card-title">
            {user.role === "student" ? "Курсы вашего класса" : "Ваши преподаваемые курсы"}
          </h2>
          {courses.length === 0 ? (
            <p>Нет доступных курсов</p>
          ) : (
            <ul className="list-group">
              {courses.map((course) => (
                <li key={course.id} className="list-group-item">
                  <strong>{course.name}</strong>
                  {user.role === "student" && (
                    <div>
                      <p>
                        Статус: {enrollments.some((e) => e.courseId === course.id) ? "Записан" : "Не записан"}
                      </p>
                      <h6>Тесты:</h6>
                      {tests.filter((t) => t.courseId === course.id).length === 0 ? (
                        <p>Тестов нет</p>
                      ) : (
                        <ul>
                          {tests
                            .filter((t) => t.courseId === course.id)
                            .map((test) => (
                              <li key={test.id}>
                                <Link to={`/take-test/${test.id}`}>
                                  {test.title}
                                  {enrollments.some((e) => e.courseId === course.id)
                                    ? ""
                                    : " (Требуется запись)"}
                                </Link>
                              </li>
                            ))}
                        </ul>
                      )}
                      // Для студентов: файлы от учителя
<h6>Файлы от учителя:</h6>
{files.filter((f) => f.courseId === course.id).length === 0 ? (
  <p>Файлов нет</p>
) : (
  <ul>
    {files.filter((f) => f.courseId === course.id).map((file) => (
      <li key={file.id}>
        <a href={`http://localhost:3002/download/${file.filename}`} download={file.originalName}>
          {file.originalName}
        </a>
      </li>
    ))}
  </ul>
)}

// Для студентов: их загруженные файлы
<h6>Ваши загруженные файлы:</h6>
{studentUploads.filter((u) => u.courseId === course.id).length === 0 ? (
  <p>Вы еще не загрузили файлы</p>
) : (
  <ul>
    {studentUploads.filter((u) => u.courseId === course.id).map((upload) => (
      <li key={upload.id}>
        <a href={`http://localhost:3002/download/${upload.filename}`} download={upload.originalName}>
          {upload.originalName}
        </a>
      </li>
    ))}
  </ul>
)}

// Для учителей: их файлы
<h6>Ваши файлы:</h6>
{files.filter((f) => f.courseId === course.id).length === 0 ? (
  <p>Файлов нет</p>
) : (
  <ul>
    {files.filter((f) => f.courseId === course.id).map((file) => (
      <li key={file.id}>
        <a href={`http://localhost:3002/download/${file.filename}`} download={file.originalName}>
          {file.originalName}
        </a>
      </li>
    ))}
  </ul>
)}

// Для учителей: файлы студентов
<h6>Файлы студентов:</h6>
{studentUploads.filter((u) => u.courseId === course.id).length === 0 ? (
  <p>Студенты еще не загрузили файлы</p>
) : (
  <ul>
    {studentUploads.filter((u) => u.courseId === course.id).map((upload) => (
      <li key={upload.id}>
        <a href={`http://localhost:3002/download/${upload.filename}`} download={upload.originalName}>
          {upload.originalName} (Студент ID: {upload.userId})
        </a>
      </li>
    ))}
  </ul>
)}
                    </div>
                  )}
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

export default Courses;
